var fahh = new Audio("data:audio/mp3;base64,")
var vineboom = new Audio("data:audio/mp3;base64, ")
var chickenscream = new Audio("data:audio/mp3;base64, ")
var metalpipe = new Audio("data:audio/mp3;base64, ")
var getout = new Audio("data:audio/mp3;base64, ")
var dundundun = new Audio("data:audio/mp3;base64, ")
var siren = new Audio("data:audio/mp3;base64, ") 
const allsounds = [fahh, vineboom, chickenscream, metalpipe, getout, dundundun, siren ];

// RIGHT
async function run() {


  const model = await roboflow.auth({ publishable_key: "rf_LSdumIOTyfdnblA3TprEXVpMvUs1" })
      .load({ model: "squirrel-kgcpd", version: 1 });

    const video = document.getElementById('videoElement');


    await new Promise((resolve) => {
      if (video.readyState >= 2) {
        resolve(); // already ready
      } else {
        video.addEventListener('loadeddata', resolve);
      }
    });

    const predictions = await model.detect(video);
    console.log("weeee")
    console.log(predictions);
    if (predictions.length > 0){
      if ((predictions[0].class == "squirrel") && (predictions[0].confidence>0.7)){
        var csound = allsounds[Math.floor(Math.random() * allsounds.length)]
        csound.play()
      }
    }


  
  
}
setInterval(function() { run(); }, 500);

